class Solution(object):
    def minAbsDiff(self, grid, k):
        m, n = len(grid), len(grid[0])
        rows = m - k + 1
        cols = n - k + 1
        ans = [[0] * cols for _ in range(rows)]

        for i in range(rows):
            for j in range(cols):
                # Extract and sort the k x k submatrix values
                vals = sorted(
                    grid[i+r][j+c]
                    for r in range(k)
                    for c in range(k)
                )
                # Remove duplicates to find distinct values
                # Minimum absolute diff between any two distinct values
                best = float('inf')
                prev = None
                for v in vals:
                    if prev is not None and v != prev:
                        best = min(best, v - prev)
                    prev = v
                ans[i][j] = 0 if best == float('inf') else best

        return ans
